use super::*;

#[cfg(feature = "native-backend")]
static EMPTY_VEC_STRING: Vec<String> = Vec::new();

#[cfg(feature = "native-backend")]
#[inline]
fn is_cold_module_chunk_function(name: &str) -> bool {
    name.contains("__molt_module_chunk_")
}

#[cfg(feature = "native-backend")]
fn loop_start_has_index_prelude(ops: &[OpIR], start_idx: usize) -> bool {
    let mut scan_idx = start_idx + 1;
    while let Some(next) = ops.get(scan_idx) {
        let kind = next.kind.as_str();
        if kind == "loop_index_start" {
            return true;
        }
        if kind.starts_with("const") {
            scan_idx += 1;
            continue;
        }
        return false;
    }
    false
}

/// Scan a loop body (from `start_idx+1` to the matching `loop_end`) and return
/// the set of list variable names whose data_ptr/len can be hoisted before the
/// loop.  A variable is hoistable when it is accessed (via `index` or
/// `store_index`) and NOT mutated (by `list_append`, `list_pop`, `list_extend`,
/// `list_insert`, `list_remove`, or `list_clear`) anywhere in the loop body.
///
/// Returns `(list_int_hoistable, list_generic_hoistable)`.
#[cfg(feature = "native-backend")]
fn scan_loop_hoistable_lists(
    ops: &[OpIR],
    start_idx: usize,
) -> (BTreeSet<String>, BTreeSet<String>) {
    let mut list_int_accessed: BTreeSet<String> = BTreeSet::new();
    let mut list_generic_accessed: BTreeSet<String> = BTreeSet::new();
    let mut mutated: BTreeSet<String> = BTreeSet::new();

    let mut depth = 0i32;
    for idx in (start_idx + 1)..ops.len() {
        let op = &ops[idx];
        match op.kind.as_str() {
            "loop_start" | "loop_index_start" => depth += 1,
            "loop_end" if depth > 0 => depth -= 1,
            "loop_end" => break,
            _ => {}
        }
        // Only consider ops at the current loop nesting level (depth == 0).
        // Inner loop accesses get their own hoisting when their loop_start is
        // processed.
        if depth != 0 {
            continue;
        }
        let args = match op.args.as_ref() {
            Some(a) if !a.is_empty() => a,
            _ => continue,
        };
        match op.kind.as_str() {
            "index" | "store_index" => {
                match op.container_type.as_deref() {
                    Some("list_int") => { list_int_accessed.insert(args[0].clone()); }
                    Some("list") => { list_generic_accessed.insert(args[0].clone()); }
                    _ => {}
                }
            }
            "list_append" | "list_pop" | "list_extend" | "list_insert"
            | "list_remove" | "list_clear" => {
                mutated.insert(args[0].clone());
            }
            _ => {}
        }
    }
    list_int_accessed.retain(|v| !mutated.contains(v));
    list_generic_accessed.retain(|v| !mutated.contains(v));
    (list_int_accessed, list_generic_accessed)
}

#[cfg(feature = "native-backend")]
#[derive(Clone, Copy, Debug, Eq, PartialEq)]
enum ScalarLane {
    Int,
    Bool,
    Float,
    Str,
}

#[cfg(feature = "native-backend")]
#[inline]
fn name_is_int_like(
    name: &str,
    int_like_vars: &BTreeSet<String>,
    bool_like_vars: &BTreeSet<String>,
) -> bool {
    int_like_vars.contains(name) || bool_like_vars.contains(name)
}

#[cfg(feature = "native-backend")]
fn infer_scalar_lane(
    op: &OpIR,
    int_like_vars: &BTreeSet<String>,
    bool_like_vars: &BTreeSet<String>,
    float_like_vars: &BTreeSet<String>,
    str_like_vars: &BTreeSet<String>,
) -> Option<ScalarLane> {
    let shift_op = matches!(op.kind.as_str(), "lshift" | "rshift" | "shl" | "shr");
    if !shift_op && let Some(type_hint) = op.type_hint.as_deref() {
        match type_hint {
            "bool" => return Some(ScalarLane::Bool),
            "int" => return Some(ScalarLane::Int),
            "float" => return Some(ScalarLane::Float),
            "str" | "string" => return Some(ScalarLane::Str),
            _ => {}
        }
    }
    let first_source = || {
        op.var.as_deref().or_else(|| {
            op.args
                .as_ref()
                .and_then(|args| args.first())
                .map(String::as_str)
        })
    };
    let args = op.args.as_deref().unwrap_or(&[]);
    let args_all =
        |pred: &dyn Fn(&str) -> bool| !args.is_empty() && args.iter().all(|arg| pred(arg));
    let args_any = |pred: &dyn Fn(&str) -> bool| args.iter().any(|arg| pred(arg));
    let is_float = |name: &str| float_like_vars.contains(name);
    let is_str = |name: &str| str_like_vars.contains(name);
    let is_int = |name: &str| name_is_int_like(name, int_like_vars, bool_like_vars);
    match op.kind.as_str() {
        "const" | "loop_index_start" | "loop_index_next" | "len" => Some(ScalarLane::Int),
        "gpu_thread_id" | "gpu_block_id" | "gpu_block_dim" | "gpu_grid_dim" => {
            Some(ScalarLane::Int)
        }
        "const_bool" => Some(ScalarLane::Bool),
        "const_float" => Some(ScalarLane::Float),
        "const_str" => Some(ScalarLane::Str),
        "copy" | "copy_var" | "load_var" | "identity_alias" => first_source().and_then(|src| {
            if int_like_vars.contains(src) {
                Some(ScalarLane::Int)
            } else if bool_like_vars.contains(src) {
                Some(ScalarLane::Bool)
            } else if float_like_vars.contains(src) {
                Some(ScalarLane::Float)
            } else if str_like_vars.contains(src) {
                Some(ScalarLane::Str)
            } else {
                None
            }
        }),
        "lt" | "le" | "gt" | "ge" | "eq" | "ne" | "is" => Some(ScalarLane::Bool),
        "bool" | "cast_bool" | "builtin_bool" | "is_truthy" | "not" => {
            first_source().and_then(|src| {
                if bool_like_vars.contains(src) {
                    Some(ScalarLane::Bool)
                } else if name_is_int_like(src, int_like_vars, bool_like_vars) {
                    Some(ScalarLane::Int)
                } else {
                    None
                }
            })
        }
        "if" => first_source().and_then(|src| {
            if bool_like_vars.contains(src) {
                Some(ScalarLane::Bool)
            } else if name_is_int_like(src, int_like_vars, bool_like_vars) {
                Some(ScalarLane::Int)
            } else {
                None
            }
        }),
        "add" | "inplace_add" => {
            if args_all(&is_str) {
                Some(ScalarLane::Str)
            } else if args_all(&is_float)
                || (args_any(&is_float) && args.iter().all(|arg| is_float(arg) || is_int(arg)))
            {
                Some(ScalarLane::Float)
            } else if args_all(&is_int) {
                Some(ScalarLane::Int)
            } else {
                None
            }
        }
        "sub" | "mul" | "inplace_sub" | "inplace_mul" | "floordiv" | "mod" | "mod_"
        | "inplace_floordiv" | "inplace_mod" | "bit_and" | "bit_or" | "bit_xor" | "bitand"
        | "bitor" | "bitxor" | "inplace_bit_and" | "inplace_bit_or" | "inplace_bit_xor" => {
            if args_all(&is_float)
                || (args_any(&is_float) && args.iter().all(|arg| is_float(arg) || is_int(arg)))
            {
                Some(ScalarLane::Float)
            } else if args_all(&is_int) {
                Some(ScalarLane::Int)
            } else {
                None
            }
        }
        // Python true division (`/`) always returns float.  For the codegen
        // fast-path we return Float only when both operands are already proven
        // float (so the handler can use raw f64 shadows directly).  When
        // operands are int the handler takes the int→f64 conversion path
        // instead, which is also correct but uses a different code sequence.
        "div" => {
            if args_all(&is_float)
                || (args_any(&is_float) && args.iter().all(|arg| is_float(arg) || is_int(arg)))
            {
                Some(ScalarLane::Float)
            } else {
                None
            }
        }
        "lshift" | "rshift" | "shl" | "shr" => None,
        "neg" | "pos" | "abs" | "builtin_abs" => first_source().and_then(|src| {
            if float_like_vars.contains(src) {
                Some(ScalarLane::Float)
            } else if name_is_int_like(src, int_like_vars, bool_like_vars) {
                Some(ScalarLane::Int)
            } else {
                None
            }
        }),
        "invert" => first_source()
            .filter(|src| name_is_int_like(src, int_like_vars, bool_like_vars))
            .map(|_| ScalarLane::Int),
        // Container indexing: the INDEX (second arg) determines the lane,
        // not the container (first arg).  When the index is proven int we
        // route to molt_list_getitem_int_fast / molt_list_setitem_int_fast
        // which skip tag-checking the index and avoid the full molt_index
        // dispatch.
        "index" | "store_index" | "dict_set" => args
            .get(1)
            .filter(|k| name_is_int_like(k, int_like_vars, bool_like_vars))
            .map(|_| ScalarLane::Int),
        _ => None,
    }
}

#[cfg(feature = "native-backend")]
#[inline]
fn shadow_value_for(
    builder: &mut FunctionBuilder<'_>,
    raw_int_shadow: &BTreeMap<String, Variable>,
    raw_int_shadow_vals: &BTreeMap<String, Value>,
    name: &str,
) -> Option<Value> {
    raw_int_shadow_vals
        .get(name)
        .copied()
        .or_else(|| raw_int_shadow.get(name).map(|&var| builder.use_var(var)))
}

#[cfg(feature = "native-backend")]
#[inline]
fn shadow_value_var_only(
    builder: &mut FunctionBuilder<'_>,
    raw_int_shadow: &BTreeMap<String, Variable>,
    name: &str,
) -> Option<Value> {
    raw_int_shadow.get(name).map(|&var| builder.use_var(var))
}

#[cfg(feature = "native-backend")]
#[inline]
fn shadow_pair_available(
    raw_int_shadow: &BTreeMap<String, Variable>,
    raw_int_shadow_vals: &BTreeMap<String, Value>,
    lhs: &str,
    rhs: &str,
) -> bool {
    (raw_int_shadow_vals.contains_key(lhs) || raw_int_shadow.contains_key(lhs))
        && (raw_int_shadow_vals.contains_key(rhs) || raw_int_shadow.contains_key(rhs))
}

