                                        // Also cache len
                                        let len = builder.ins().load(
                                            types::I64,
                                            MemFlags::trusted(),
                                            storage_ptr,
                                            LIST_INT_STORAGE_LEN_OFFSET,
                                        );
                                        let lvar = builder.declare_var(types::I64);
                                        builder.def_var(lvar, len);
