                                seal_block_once(&mut builder, &mut sealed_blocks, slow_block);
                                let callee = Self::import_func_id_split(
                                    &mut self.module,
                                    &mut self.import_ids,
                                    "molt_list_int_getitem",
                                    &[types::I64, types::I64],
                                    &[types::I64],
                                );
                                let local_callee =
                                    self.module.declare_func_in_func(callee, builder.func);
