                                            builder.def_var(var, dp);
                                            list_data_cache.insert(args[0].clone(), var);
                                            let lvar = builder.declare_var(types::I64);
                                            builder.def_var(lvar, len);
                                            list_len_cache.insert(args[0].clone(), lvar);
